import React, { useState, useEffect } from 'react';
import { Typography, Card, CardHeader, CardMedia, CardContent, Divider } from '@mui/material';
import { Link, useParams } from 'react-router-dom';
import fetchModel from '../../lib/fetchModelData';
import './styles.css';

function UserPhotos({ setContext }) {
  const { userId } = useParams();
  const [photos, setPhotos] = useState([]);
  const [user, setUser] = useState(null);

  useEffect(() => {
    // 1. Lấy thông tin user để hiển thị trên TopBar
    fetchModel(`/user/${userId}`)
      .then((response) => {
        setUser(response.data);
        setContext(`Ảnh của ${response.data.first_name} ${response.data.last_name}`);
      })
      .catch((err) => console.error("Lỗi lấy thông tin user:", err));

    // 2. Lấy danh sách ảnh của user đó
    fetchModel(`/photosOfUser/${userId}`)
      .then((response) => {
        setPhotos(response.data);
      })
      .catch((err) => console.error("Lỗi lấy ảnh:", err));
  }, [userId, setContext]);

  if (!user) {
    return <Typography>Đang tải dữ liệu...</Typography>;
  }

  return (
    <div className="photos-container">
      {photos.length > 0 ? (
        photos.map((photo) => (
          <Card key={photo._id} style={{ marginBottom: '30px' }} elevation={3}>
            <CardHeader 
              title={`Đăng lúc: ${new Date(photo.date_time).toLocaleString()}`} 
            />

            {/* Gắn ảnh - lưu ý: vì Bài 2 dùng server, ảnh thường được truy cập qua đường dẫn tĩnh */}
            <CardMedia
              component="img"
              image={require(`../../images/${photo.file_name}`)}
              alt="User Photo"
            />

            <CardContent>
              <Typography variant="h6">Bình luận:</Typography>
              <Divider style={{ margin: '10px 0' }} />

              {photo.comments ? photo.comments.map((comment) => (
                <div key={comment._id} style={{ marginBottom: '15px', borderLeft: '3px solid #1976d2', paddingLeft: '10px' }}>
                  <Typography variant="subtitle2">
                    <Link to={`/users/${comment.user._id}`} style={{ textDecoration: 'none', fontWeight: 'bold' }}>
                      {comment.user.first_name} {comment.user.last_name}
                    </Link>
                    <span style={{ color: 'gray', marginLeft: '10px', fontSize: '0.8rem' }}>
                      {new Date(comment.date_time).toLocaleString()}
                    </span>
                  </Typography>
                  <Typography variant="body2" style={{ marginTop: '5px' }}>
                    {comment.comment}
                  </Typography>
                </div>
              )) : (
                <Typography variant="body2" color="textSecondary">Chưa có bình luận nào.</Typography>
              )}
            </CardContent>
          </Card>
        ))
      ) : (
        <Typography variant="h6">Người dùng này chưa đăng ảnh nào.</Typography>
      )}
    </div>
  );
}

export default UserPhotos;
